mapper.update:
update faq_tbl set
	faq_title = #{faqTitle},
	faq_content = #{faqContent},
	faq_category = #{faqCategory}
where faq_no = #{faqNo}

mapper.select:
SELECT m.member_id, m.member_name, m.member_nickname, m.member_email, m.member_grade, m.member_thumb, m.member_status, to_char(m.enroll_date, 'YYYY-MM-DD') as enrollDate, -- 게시글/댓글/신고 수는 서브쿼리로 각각 카운트 (SELECT COUNT(*) FROM board_tbl b WHERE b.writer_id = m.member_id) AS boardCount, (SELECT COUNT(*) FROM board_comment_tbl c WHERE c.board_comment_writer = m.member_id) AS commentCount, (SELECT COUNT(*) FROM board_report_tbl r JOIN board_tbl b ON r.board_no = b.board_no WHERE b.writer_id = m.member_id) AS reportCount, (SELECT COUNT(*) FROM member_log_tbl l WHERE l.member_id = m.member_id AND l.log_action = '로그인실패' AND l.log_time >= SYSDATE - 1) AS failCount, (SELECT COUNT(*) FROM member_log_tbl l WHERE l.member_id = m.member_id AND l.log_alert = '위치변경' AND l.log_time >= SYSDATE - 1) AS locationChangeCount FROM member_tbl1 m
m.member_status = #{status}
AND m.member_grade = #{grade}
AND (m.member_id LIKE '%'||#{keyword}||'%' OR m.member_name LIKE '%'||#{keyword}||'%')
ORDER BY m.enroll_date DESC


select * from (
	select member_log_no, log_ip, log_time, log_action, log_detail
	from member_log_tbl
	where member_id = #{memberId}
	order by log_time desc
) where rownum <= 4

select member_log_no, log_ip, log_time, log_action, log_detail, log_device, log_location, log_result, log_alert from member_log_tbl where member_id = #{memberId}
and log_action = #{action}
and log_result = #{result}
order by log_time ${sort} offset #{start} rows fetch next 20 rows only
